<script setup>
  import Back from "@/components/back/index.vue";
  import { gsap } from "gsap";
  import { MorphSVGPlugin } from "gsap/MorphSVGPlugin";
  import { GSDevTools } from "gsap/GSDevTools";
  import { onBeforeUnmount, onMounted } from "vue";

  let timeLineItem = null;
  gsap.registerPlugin(MorphSVGPlugin, GSDevTools);
  onMounted(() => {
    init();
  });

  onBeforeUnmount(() => {
    if (timeLineItem) {
      timeLineItem.kill();
      timeLineItem = null;
    }
    const main = GSDevTools.getById("mainDevTools");
    if (main) {
      main.kill();
    }
  });
  const init = () => {
    const shapes = gsap.utils.toArray(".shape");

    timeLineItem = gsap.timeline({
      defaults: { duration: 2, ease: "expo.inOut" },
      repeat: -1,
      id: "morph",
    });
    // console.log("timeLineItem", timeLineItem);
    shapes.forEach((_shape, i) => {
      timeLineItem.to("#morph", { morphSVG: shapes[i] });
    });

    // gsap.to("#morph", {
    //   duration: 2,
    //   ease: "expo.inOut",
    //   morphSVG: "#chess",
    // });
    GSDevTools.create({
      animation: timeLineItem,
      id: "mainDevTools",
    });
  };
</script>

